import Foundation

func solve(nums: Array<Int64>, queries: Array<Array<Int64>>) -> Int64 {
    let mod = 109 + 7
    for query in queries {
        let li = query[0]
        let ri = query[1]
        let ki = query[2]
        let vi = query[3]
        var idx = li
        while idx <= ri {
            nums[idx] = (nums[idx] * vi) % mod
            idx += ki
        }
    }
    var xorResult = Int64(0)
    for num in nums {
        xorResult ^= num
    }
    return xorResult
}
